import React, { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  detectDateRangePreset,
  SearchTextInput,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useViewMobileLayout,
  useErpListSelection,
  type ErpListTableConfig,
  formatMoneyVnd,
  formatUTCToLocalDisplay,
} from '@linm-soft-org/linm-web-common-components';
import { VoucherStatusBadge } from '../voucher/VoucherStatusBadge';
import { useAppDispatch } from '../../store/hooks';
import { bhService } from '../../services/bh/bhService';
import type { DeliveryDto } from '../../services/bh/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
} from '../../utils/voucherListRowMenuHint';
import { canEditDeliveryFromListRow } from '../../utils/deliveryListRowActions';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list/VoucherRowActionMenu';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import erp from '../../styles/erpPage.module.css';

const TEST_ID = 'bh-xuat-hang';
const PAGE_ID = 'bh-xuat-hang';
const CREATE_FORM = 'create-sales-delivery';

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Posted', label: 'Đã ghi sổ' },
  { value: 'Cancelled', label: 'Đã hủy' },
];

const LIST_COLUMNS = [
  { id: 'code', label: 'Số phiếu' },
  { id: 'deliveryDate', label: 'Ngày' },
  { id: 'customerName', label: 'Khách hàng' },
  { id: 'warehouseName', label: 'Kho' },
  { id: 'totalAmount', label: 'Tổng tiền' },
  { id: 'status', label: 'Trạng thái' },
] as const;

function filterBySearch(rows: DeliveryDto[], search: string): DeliveryDto[] {
  const q = search.trim().toLowerCase();
  if (!q) return rows;
  return rows.filter(
    r =>
      r.code.toLowerCase().includes(q) ||
      (r.customerName ?? '').toLowerCase().includes(q) ||
      (r.warehouseName ?? '').toLowerCase().includes(q),
  );
}

export const XuatHangList: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const {
    initialized,
    fromDate,
    toDate,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.xuatHang);
  const [items, setItems] = useState<DeliveryDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(TEST_ID),
  );
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: DeliveryDto } | null>(null);
  const [posting, setPosting] = useState(false);

  const { canCreate, canUpdate, canApprove } = useVoucherListActions(CREATE_FORM);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: r => r.status === 'Draft',
  });

  const activeRow = selection.activeRow;
  const canPostActive = Boolean(activeRow?.status === 'Draft' && canApprove);
  const canViewActive = Boolean(activeRow);
  const canEditActive = Boolean(activeRow && activeRow.status === 'Draft' && canUpdate);
  const hasFormRoute = true;

  const navigateToRow = useCallback(
    (rowId: string, edit = false) => {
      navigate(`/bh/xuat-hang/${rowId}${edit ? '?edit=1' : ''}`);
    },
    [navigate],
  );

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService
        .getDeliveries({
          fromDate,
          toDate,
          status: status || undefined,
          page,
          pageSize,
        })
        .then(res => {
          if (cancelled) return;
          const filtered = filterBySearch(res.items, search);
          setItems(filtered);
          setTotalCount(search.trim() ? filtered.length : res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải danh sách phiếu xuất hàng'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [initialized, fromDate, toDate, status, page, pageSize, search, reloadKey, dispatch]);

  const handlePostActive = async () => {
    if (!activeRow || activeRow.status !== 'Draft') return;
    setPosting(true);
    try {
      await bhService.postDelivery(activeRow.id);
      dispatchAppToast(dispatch, { message: 'Ghi sổ phiếu xuất hàng thành công', type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Ghi sổ thất bại'),
        type: 'error',
      });
    } finally {
      setPosting(false);
    }
  };

  const handleSaveTableConfig = (config: ErpListTableConfig) => {
    setTableConfig(config);
    saveErpListTableConfig(TEST_ID, config);
    setShowConfigModal(false);
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: DeliveryDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      setRowMenu(null);
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit' && canEditDeliveryFromListRow(row.status, canUpdate)) {
        navigateToRow(row.id, true);
      }
    },
    [rowMenu?.row, canUpdate, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow
    ? canEditDeliveryFromListRow(rowMenuRow.status, canUpdate)
    : false;

  const renderCell = (row: DeliveryDto, colId: string) => {
    switch (colId) {
      case 'code':
        return (
          <button
            type="button"
            className={erp.codeLink}
            data-testid={`${TEST_ID}-row-${row.id}-code`}
            onClick={e => {
              e.stopPropagation();
              navigateToRow(row.id);
            }}
          >
            {row.code}
          </button>
        );
      case 'deliveryDate':
        return formatUTCToLocalDisplay(row.deliveryDate, false);
      case 'customerName':
        return row.customerName;
      case 'warehouseName':
        return row.warehouseName;
      case 'totalAmount':
        return <span className={erp.colRight}>{formatMoneyVnd(row.totalAmount)}</span>;
      case 'status':
        return <VoucherStatusBadge status={row.status} />;
      default:
        return null;
    }
  };

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canApprove: canPostActive,
      approveDisabled: !canPostActive || posting,
      onApprove: handlePostActive,
      canViewLedger: false,
      canPrint: false,
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate: hasFormRoute && canCreate,
      onCreate: () => navigate('/bh/xuat-hang/them'),
      onEditConfig: () => setShowConfigModal(true),
    }),
    [
      canPostActive,
      posting,
      canCreate,
      canViewActive,
      canEditActive,
      activeRow,
      refresh,
      navigate,
      navigateToRow,
      handlePostActive,
    ],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm số phiếu, khách hàng, kho..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => {
                  setStatus(e.target.value);
                  resetPage();
                }}
                options={STATUS_OPTIONS}
                data-testid={`${TEST_ID}-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      searchDraft,
      fromDate,
      toDate,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      setStatus,
      handleSearch,
      showTableLoading,
    ],
  );

  const batchBar =
    selection.selectedCount > 0 ? (
      <div className={erp.batchBar} data-testid={`${TEST_ID}-batch-bar`}>
        <span>Đã chọn {selection.selectedCount}</span>
        <button
          type="button"
          className={erp.batchBarLink}
          data-testid={`${TEST_ID}-batch-clear`}
          onClick={selection.clearSelection}
        >
          Bỏ chọn tất cả
        </button>
      </div>
    ) : null;

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <p>Không có phiếu xuất hàng</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table-wrapper`}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th className={erp.colCheck}>
                <span className="sr-only">Chọn</span>
              </th>
              {LIST_COLUMNS.map(col => (
                <th key={col.id}>{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map(row => {
              const isActive = selection.isRowActive(row);
              const isChecked = selection.isRowChecked(row);
              return (
                <tr
                  key={row.id}
                  className={[isChecked ? erp.catalogRowChecked : '', isActive ? erp.catalogRowActive : '']
                    .filter(Boolean)
                    .join(' ')}
                  onClick={() => selection.selectActiveRow(row)}
                  onContextMenu={e => {
                    e.preventDefault();
                    handleRowOpenActionMenu({ row, x: e.clientX, y: e.clientY });
                  }}
                  data-testid={`${TEST_ID}-row-${row.id}`}
                >
                  <td className={erp.colCheck}>
                    {row.status === 'Draft' ? (
                      <input
                        type="checkbox"
                        checked={isChecked}
                        onChange={() => selection.toggleRow(row, !isChecked)}
                        onClick={e => e.stopPropagation()}
                        data-testid={`${TEST_ID}-row-${row.id}-check`}
                      />
                    ) : null}
                  </td>
                  {LIST_COLUMNS.map(col => (
                    <td key={col.id}>{renderCell(row, col.id)}</td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
        <p className={erp.rowMenuHint} data-testid={`${TEST_ID}-row-menu-hint`}>
          {rowMenuHintMessage}
        </p>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: 'Phiếu xuất hàng',
          titleIconClass: 'fas fa-truck-loading',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={batchBar}
        listTitle="Danh sách phiếu xuất hàng"
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => {
              setPage(p);
              selection.clearSelection();
            }}
            onPageSizeChange={setPageSize}
          />
        }
        modals={
          <>
            <LinListTableConfigModal
              isOpen={showConfigModal}
              onClose={() => setShowConfigModal(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView={false}
              showEdit={rowMenuShowEdit && hasFormRoute}
              showViewLedger={false}
              showPrint={false}
            />
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default XuatHangList;
